import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Privacy-Preserving ML",
  subtitle: "Federated learning and differential privacy for secure AI analytics",
  description: "Train powerful AI models without compromising user privacy. Our privacy-preserving machine learning framework uses federated learning and differential privacy to derive insights from distributed data sources while keeping data localized. The AI Security Copilot enables natural language queries for security insights.",
  benefits: [
    "Federated learning for distributed model training across organizations",
    "Differential privacy implementation with mathematical guarantees",
    "AI Security Copilot for natural language security queries",
    "Data remains localized during training - never leaves your infrastructure",
    "GDPR-compliant AI analytics with built-in privacy controls"
  ],
  features: [
    { title: "Federated Learning", description: "Train models across distributed data sources without data sharing" },
    { title: "Differential Privacy", description: "Add noise to prevent individual identification" },
    { title: "AI Copilot", description: "Natural language interface for security analytics" },
    { title: "Secure Aggregation", description: "Combine model updates without exposing raw data" },
    { title: "Privacy Auditing", description: "Tools to verify privacy guarantees are maintained" }
  ],
  howItWorks: [
    { title: "Local Training", description: "Models train on local data at each location" },
    { title: "Secure Aggregation", description: "Only model updates are shared, not raw data" },
    { title: "Differential Privacy", description: "Mathematical noise prevents individual identification" },
    { title: "Global Insights", description: "Gain insights from all data without compromising privacy" }
  ],
  color: "#ec4899",
  icon: "M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z",
  gradient: "from-pink-500 to-rose-500"
};

function PrivacyML() {
  return <FeatureDetail {...pageData} />;
}

export default PrivacyML;
